# samlsp/saml.py
import base64
import binascii
import datetime
from xml.etree import ElementTree as ET
from django.conf import settings

NS = {
    "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
    "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
}

class SAMLValidationError(Exception):
    pass

def _parse_time(value):
    if not value:
        return None
    try:
        if value.endswith("Z"):
            value = value[:-1] + "+00:00"
        return datetime.datetime.fromisoformat(value)
    except Exception:
        return None

def decode_saml_response(encoded_response):
    try:
        xml_bytes = base64.b64decode(encoded_response)
    except (binascii.Error, ValueError) as exc:
        raise SAMLValidationError("Invalid base64 SAMLResponse") from exc
    try:
        root = ET.fromstring(xml_bytes)
    except ET.ParseError as exc:
        raise SAMLValidationError("Invalid XML in SAMLResponse") from exc
    return root

def basic_validate_response(root):
    if root.tag != f"{{{NS['samlp']}}}Response":
        raise SAMLValidationError("Root element must be samlp:Response")

    status_code = root.find("./samlp:Status/samlp:StatusCode", NS)
    if status_code is None:
        raise SAMLValidationError("Missing SAML StatusCode")
    if status_code.attrib.get("Value") != "urn:oasis:names:tc:SAML:2.0:status:Success":
        raise SAMLValidationError("SAML status is not Success")

    assertion = root.find("./saml:Assertion", NS)
    if assertion is None:
        raise SAMLValidationError("Missing Assertion")

    subject = assertion.find("./saml:Subject", NS)
    if subject is None:
        raise SAMLValidationError("Missing Subject")

    name_id = subject.find("./saml:NameID", NS)
    if name_id is None or not (name_id.text and name_id.text.strip()):
        raise SAMLValidationError("Missing NameID")

    conditions = assertion.find("./saml:Conditions", NS)
    if conditions is not None:
        now = datetime.datetime.now(datetime.timezone.utc)
        not_before = _parse_time(conditions.attrib.get("NotBefore"))
        not_on_or_after = _parse_time(conditions.attrib.get("NotOnOrAfter"))
        if not_before and now < not_before.astimezone(datetime.timezone.utc):
            raise SAMLValidationError("Assertion not yet valid")
        if not_on_or_after and now >= not_on_or_after.astimezone(datetime.timezone.utc):
            raise SAMLValidationError("Assertion expired")

        audience_restriction = conditions.find("./saml:AudienceRestriction/saml:Audience", NS)
        expected_audience = settings.SAML_SP.get("EXPECTED_AUDIENCE")
        if audience_restriction is not None and expected_audience:
            audience = (audience_restriction.text or "").strip()
            if audience != expected_audience:
                raise SAMLValidationError("Audience mismatch")

    subject_confirmation_data = assertion.find(
        "./saml:Subject/saml:SubjectConfirmation/saml:SubjectConfirmationData", NS
    )
    if subject_confirmation_data is not None:
        recipient = subject_confirmation_data.attrib.get("Recipient")
        expected_recipient = settings.SAML_SP.get("EXPECTED_RECIPIENT")
        if expected_recipient and recipient and recipient != expected_recipient:
            raise SAMLValidationError("Recipient mismatch")
        not_on_or_after = _parse_time(subject_confirmation_data.attrib.get("NotOnOrAfter"))
        if not_on_or_after:
            now = datetime.datetime.now(datetime.timezone.utc)
            if now >= not_on_or_after.astimezone(datetime.timezone.utc):
                raise SAMLValidationError("Subject confirmation expired")

    return assertion

def extract_nameid(assertion):
    node = assertion.find("./saml:Subject/saml:NameID", NS)
    if node is None or not node.text:
        raise SAMLValidationError("Missing NameID")
    return node.text.strip()

def extract_attributes(assertion):
    result = {}
    for attr in assertion.findall(".//saml:AttributeStatement/saml:Attribute", NS):
        attr_name = attr.attrib.get("Name") or attr.attrib.get("FriendlyName")
        if not attr_name:
            continue
        values = []
        for value_node in attr.findall("./saml:AttributeValue", NS):
            if value_node.text is not None:
                values.append(value_node.text.strip())
        if values:
            result[attr_name] = values if len(values) > 1 else values[0]
    return result

def map_user_fields(nameid, attributes):
    mapped = {
        "username": None,
        "email": "",
        "first_name": "",
        "last_name": "",
    }
    attribute_map = settings.SAML_SP.get("ATTRIBUTE_MAP", {})
    for target_field, candidate_names in attribute_map.items():
        for candidate in candidate_names:
            if candidate in attributes:
                value = attributes[candidate]
                if isinstance(value, list):
                    value = value[0] if value else ""
                mapped[target_field] = value
                break

    if not mapped["username"]:
        configured = settings.SAML_SP.get("NAMEID_ATTRIBUTE", "username")
        if configured == "username":
            mapped["username"] = nameid
        else:
            mapped[configured] = nameid
            mapped["username"] = nameid

    return mapped

# samlsp/views.py
from django.conf import settings
from django.contrib.auth import get_user_model, login, logout
from django.contrib.auth.decorators import login_required
from django.http import HttpResponse, HttpResponseBadRequest, JsonResponse
from django.views.decorators.csrf import csrf_exempt
from .saml import (
    decode_saml_response,
    basic_validate_response,
    extract_nameid,
    extract_attributes,
    map_user_fields,
    SAMLValidationError,
)

User = get_user_model()

@csrf_exempt
def saml_acs(request):
    if request.method != "POST":
        return HttpResponseBadRequest("Only POST allowed")

    saml_response = request.POST.get("SAMLResponse")
    if not saml_response:
        return HttpResponseBadRequest("Missing SAMLResponse")

    try:
        root = decode_saml_response(saml_response)
        assertion = basic_validate_response(root)
        nameid = extract_nameid(assertion)
        attributes = extract_attributes(assertion)
        user_fields = map_user_fields(nameid, attributes)
    except SAMLValidationError as exc:
        return HttpResponseBadRequest(str(exc))

    username = user_fields["username"]
    if not username:
        return HttpResponseBadRequest("No username available")

    user, created = User.objects.get_or_create(
        username=username,
        defaults={
            "email": user_fields.get("email", "") or "",
            "first_name": user_fields.get("first_name", "") or "",
            "last_name": user_fields.get("last_name", "") or "",
        },
    )

    updated = False
    for field in ["email", "first_name", "last_name"]:
        incoming = user_fields.get(field, "")
        if incoming is not None and incoming != getattr(user, field):
            setattr(user, field, incoming)
            updated = True
    if created:
        user.set_unusable_password()
        updated = True
    if updated:
        user.save()

    user.backend = settings.AUTHENTICATION_BACKENDS[0]
    login(request, user)

    request.session["saml_nameid"] = nameid
    request.session["saml_attributes"] = attributes

    return JsonResponse(
        {
            "status": "authenticated",
            "username": user.username,
            "nameid": nameid,
            "attributes": attributes,
        }
    )

@login_required
def home_view(request):
    return JsonResponse(
        {
            "authenticated": True,
            "username": request.user.username,
            "nameid": request.session.get("saml_nameid"),
            "attributes": request.session.get("saml_attributes", {}),
        }
    )

def logout_view(request):
    logout(request)
    return JsonResponse({"status": "logged_out"})

def metadata_view(request):
    entity_id = settings.SAML_SP["ENTITY_ID"]
    acs_url = settings.SAML_SP["ACS_URL"]
    xml = f'''<?xml version="1.0"?>
<EntityDescriptor xmlns="urn:oasis:names:tc:SAML:2.0:metadata" entityID="{entity_id}">
  <SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    <AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" Location="{acs_url}" index="1"/>
  </SPSSODescriptor>
</EntityDescriptor>'''
    return HttpResponse(xml, content_type="application/samlmetadata+xml")

